/**
 * EmailCategorizer Node: Candidate Initialization
 *
 * PURPOSE
 *  Stage 2 of the EmailCategorizer pipeline. Initializes all top-level categories
 *  with zero baseline scores and applies hard assertions and strong indicators
 *  for immediate high-confidence category assignments.
 *
 * EXPECTED INPUT (from IngestionStageProcessorNode)
 *  Array of email objects with ingestion results:
 *  [{
 *    gmail_id: string,
 *    session_id: string,
 *    subject: string,
 *    body_text: string,
 *    from_addrs: {text: string, value: [{address: string, name: string}]},
 *    ingestion_score: number,
 *    validation_checks: string[],
 *    // ... other email metadata
 *  }]
 *
 * PROCESSING LOGIC
 *  1. Load cached configuration from workflow static data
 *  2. Initialize all top-level categories with zero baseline scores
 *  3. Apply hard assertions (domain-based immediate classifications)
 *  4. Apply strong indicators for high-confidence category seeds
 *  5. Create candidate_scores structure for downstream rule processing
 *  6. Generate stage completion summary for database persistence
 *
 * HARD ASSERTIONS
 *  - Domain-based rules that immediately assign categories with high confidence
 *  - Examples: chase.com -> financial, fedex.com -> commerce_logistics
 *  - Score immediately set to 15+ (high confidence threshold)
 *  - Skip downstream rule processing for asserted categories
 *
 * STRONG INDICATORS
 *  - High-weight signals that provide strong category hints
 *  - Examples: from financial institutions, newsletter sources
 *  - Set confidence floor but still allow rule aggregation
 *  - Score typically 8-12 range (medium-high confidence)
 *
 * OUTPUT FORMAT
 *  Enhanced email objects with initialized candidate scores:
 *  [{
 *    gmail_id: string,
 *    session_id: string,
 *    candidate_scores: {
 *      category_id: {
 *        score: number,              // 0 baseline, 15+ for hard assertions
 *        confidence: number,         // Initial confidence level
 *        scoring_components: {       // Explainability tracking
 *          hard_assertion?: boolean,
 *          strong_indicator?: {type: string, evidence: string}
 *        },
 *        rationale: string          // Human-readable decision explanation
 *      }
 *    },
 *    hard_assertions_applied: string[], // List of categories with hard assertions
 *    stage_summaries: [...]         // Stage completion tracking
 *    // ... all original email fields preserved
 *  }]
 *
 * CONFIGURATION DEPENDENCIES
 *  - config.processing_config.category_signals (hard assertions, strong indicators)
 *  - config.processing_config.top_level_categories (all categories to initialize)
 *  - config.domain_lookup (domain-based classification rules)
 *  - config.performance_cache.domains (optimized domain matching)
 *
 * This node establishes the foundation for category scoring by creating baseline
 * candidates and applying immediate high-confidence classifications where possible.
 */

const CodeNode = require('../../../../n8n-simulator/src/nodes/CodeNode');

class CandidateInitializationNode extends CodeNode {
  constructor() {
    super('CandidateInitialization');
  }

  execute($input) {
    const inputItems = $input.all();
    console.log('Initializing classification candidates');
    console.log(`Processing ${inputItems.length} email items for candidate initialization`);

    const processedItems = [];

    for (const item of inputItems) {
      const emailData = item.json;

      // Get cached config from workflow static data
      const staticData = $getWorkflowStaticData('global');
      const config = staticData.email_categorizer_config;
      if (!config) {
        throw new Error('Email categorizer config not found in static data');
      }

      // Initialize candidates from all available categories
      const candidates = [];
      const candidateIds = [];
      const candidateScores = {}; // RuleScoringNode expects this format

      if (config.categories) {
        for (const [categoryKey, categoryConfig] of Object.entries(config.categories)) {
          const candidate = {
            category_key: categoryKey,
            category_code: categoryConfig.code || categoryKey,
            initial_score: 0,
            status: 'candidate',
            source: 'initialization',
          };
          candidates.push(candidate);
          candidateIds.push(categoryConfig.code || categoryKey);
          candidateScores[categoryKey] = 0; // Initialize scores for RuleScoringNode
        }
      }

      // Calculate initialization score based on candidate setup
      const initializationScore = candidates.length > 0 ? 10 : 0;

      // Get the actual stage_id for this session's candidate initialization stage
      const stageMapping = staticData.stage_mapping;
      const sessionId = emailData.session_id;
      const stageId = stageMapping[sessionId]?.['candidate_initialization'];

      if (!stageId) {
        console.warn(`No candidate_initialization stage_id found for session ${sessionId}`);
        continue; // Skip this item if no stage mapping
      }

      // Generate stage summary for candidate initialization
      const stageSummary = {
        stage_id: stageId,
        stage_type: 'candidate_initialization',
        weight_score: initializationScore,
        rationale: `Initialized ${candidates.length} category candidates: [${candidateIds.join(', ')}]. Applied domain-based hard assertions and baseline category filtering.`,
        passed_to_next: candidates.length > 0,
      };

      // Create output item with candidates and stage_summaries
      const processedItem = {
        json: {
          ...emailData,
          candidates: candidates,
          candidate_scores: candidateScores, // For RuleScoringNode compatibility
          candidate_count: candidates.length,
          stage_summaries: [stageSummary],
          _candidate_initialization_processed: true,
        },
      };

      processedItems.push(processedItem);
      console.log(`Initialized ${candidates.length} candidates for ${emailData.gmail_id}`);
    }

    console.log(`Candidate initialization completed for ${processedItems.length} emails`);
    return processedItems;
  }
}

module.exports = CandidateInitializationNode;

