 *
 * ERROR MODES
 *  - Missing required files -> throws Error
 *  - Missing required processing_config sections / thresholds -> throws Error
 *  - Unknown domain source group referenced -> logs warning, leaves ref unexpanded
 *
 * PREVIOUS NODE: 01-load-config-files (ReadWriteFilesFromDiskNode)
 * NEXT NODE:     03-fetch-emails (PostgresSelectRows)
 *
 * Extends CodeNode from n8n-simulator for local testing and development.
 */

const CodeNode = require('../../../../n8n-simulator/src/nodes/CodeNode');
const ConfigUtils = require('../../utils/ConfigUtils');

class ProcessAndCacheConfigNode extends CodeNode {
  constructor() {
    super('ProcessAndCacheConfig');
  }

  /**
   * Main execution method - contains the business logic that would be in an n8n Code node
   * @param {Object} $input - n8n input object with .all(), .first() methods
   * @returns {Array} Array of output items in n8n format
   */
  async execute($input) {
    const inputItems = $input.all();

    console.log('Starting process_and_cache_config node execution');

    // Extract configuration files from input
    const configFiles = {};

    for (const item of inputItems) {
      // Check if item has json property and it's not null
      if (!item.json || item.json === null) {
        console.warn('Skipping item with null json property');
        continue;
      }

      const data = item.json;

      // Handle n8n item structure after MergeNode
      if (data && typeof data === 'object') {
        let fileName, configData;

        // Check for nested structure from MoveBinaryDataNode
        // The debug shows structure: item.json.json.processing_config
        if (data.json && typeof data.json === 'object') {
          // MoveBinaryDataNode created a nested structure
          const nestedData = data.json;
          configData = nestedData;

          if (nestedData.processing_config) {
            fileName = 'email-categorizer-config.json';
          } else if (nestedData.financial && nestedData.financial.domains) {
            fileName = 'domain-sources.json';
          } else {
            console.warn('Could not determine config file type from nested structure. Keys:', Object.keys(nestedData));
            continue;
          }
        } else if (data.fileName && data.data) {
          // Legacy structure with fileName and data properties
          fileName = data.fileName;
          configData = data.data;
        } else {
          // Direct structure - config data is directly in data
          configData = data;

          if (data.processing_config) {
            fileName = 'email-categorizer-config.json';
          } else if (data.financial && data.financial.domains) {
            fileName = 'domain-sources.json';
          } else {
            console.warn('Could not determine config file type from direct structure. Keys:', Object.keys(data));
            continue;
          }
        }

        const baseName = fileName.split('/').pop().replace('.json', '');

        configFiles[baseName] = configData;
        console.log(`Loaded config file: ${baseName}`);
      } else {
        console.warn('Invalid item structure - no valid data found. Item keys:', Object.keys(item));
      }
    }

    // Validate required configuration files are present
    const requiredConfigs = ['email-categorizer-config', 'domain-sources'];
    for (const required of requiredConfigs) {
      if (!configFiles[required]) {
        throw new Error(`Missing required configuration file: ${required}.json`);
      }
    }

    console.log('Processing and validating configuration structure');

    const mainConfig = configFiles['email-categorizer-config'];
    const domainSources = configFiles['domain-sources'];

    // Debug: Check if ai_prompts exists in the original config
    if (!mainConfig.ai_prompts) {
      // Fallback: Read the original config file directly to get ai_prompts
      const fs = require('fs');
      const path = require('path');
      const fullConfigPath = path.resolve(process.cwd(), 'config/email-categorizer-config.json');

      try {
        const fullConfigJson = fs.readFileSync(fullConfigPath, 'utf8');
        const fullConfig = JSON.parse(fullConfigJson);

        if (fullConfig.ai_prompts) {
          mainConfig.ai_prompts = fullConfig.ai_prompts;

          // Also add feature_extraction_schema if it exists
          if (fullConfig.feature_extraction_schema) {
            mainConfig.feature_extraction_schema = fullConfig.feature_extraction_schema;
          }
        }
      } catch (error) {
        console.error('Error reading original config file:', error.message);
      }
    }

    // Convert prompt arrays to strings if they exist (after potential fallback loading)
    if (mainConfig.ai_prompts) {
      ConfigUtils.convertPromptArraysToStrings(mainConfig.ai_prompts, console.log);
    }

    // Validate main config structure
    this._validateMainConfig(mainConfig);

    // Expand domain references in category signals
    const expandedConfig = this._expandDomainReferences(mainConfig, domainSources);

    // Build derived lookup structures for performance
    const processedConfig = this._buildLookupStructures(expandedConfig);

    // Cache the processed configuration in workflow static data
    const staticData = $getWorkflowStaticData('global');
    const email_categorizer_config = {
      config: processedConfig,
      domain_sources: domainSources,
      cache_timestamp: new Date().toISOString(),
      config_version: processedConfig.processing_config?.version || 'unknown',
      categories_count: Object.keys(processedConfig.processing_config?.category_signals || {}).length,
      domain_groups_expanded: Object.keys(processedConfig.domain_lookup || {}).length,
      attributes_count: Object.keys(processedConfig.processing_config.attributes || {}).length,
      subtypes_total: this._countSubtypes(processedConfig.processing_config.subtypes || {}),

