 *      version?: string,
 *      category_signals: {
 *        <category_name>: {
 *          <signal_name>: {
 *            // signal-specific fields, optionally:
 *            from_domains_ref?: { source_group: string, confidence?: 'high'|'medium'|'low' }
 *            from_domains?: string[]            // populated after expansion
 *          }
 *        }, ...
 *      },
 *      attributes: {
 *        <attribute_name>: {
 *          description?: string,
 *          detectors?: { type: string, pattern?: string, [k:string]: any }[],
 *          relevance?: { [roleName: string]: number }
 *        }, ...
--
 *      ],
 *      // other metadata fields allowed
 *    },
 *    metadata?: { ... } // ignored for expansion
 *  }
 *
 * PROCESSING STEPS
 *  1. Collect required config objects from input items (by basename).
 *  2. Validate presence & structural requirements of processing_config.
 *  3. Build domain_lookup: group -> { high_confidence|medium_confidence|low_confidence: [{domain,type}] }.
 *  4. Expand any signal "from_domains_ref" into a concrete list "from_domains" using domain_lookup; remove the ref.
 *  5. Derive lookup + helper structures:
 *        config.category_lookup      (category name -> {id,name,display_name})
 *        config.subtype_lookup       (category -> subtype -> enriched subtype data)
 *        config.attribute_patterns   (attribute -> {detectors, role_mapping, description})
 *        config.performance_cache    ({all_categories, <group>_domains, confidence_thresholds, attribute_names})
 *        config.domain_lookup        (as built in step 3)
 *  6. Count categories, attributes, subtypes for summary metrics.
 *  7. Store enriched structure + summary in workflow static data under staticData.email_categorizer_config.
 *
 * CACHED OBJECT (staticData.email_categorizer_config)
--
    // Convert prompt arrays to strings if they exist (after potential fallback loading)
    if (mainConfig.ai_prompts) {
      ConfigUtils.convertPromptArraysToStrings(mainConfig.ai_prompts, console.log);
    }
    // Validate main config structure
    this._validateMainConfig(mainConfig);
    // Expand domain references in category signals
    const expandedConfig = this._expandDomainReferences(mainConfig, domainSources);
    // Build derived lookup structures for performance
    const processedConfig = this._buildLookupStructures(expandedConfig);
    // Cache the processed configuration in workflow static data
    const staticData = $getWorkflowStaticData('global');
    const email_categorizer_config = {
      config: processedConfig,
      domain_sources: domainSources,
      cache_timestamp: new Date().toISOString(),
--
        if (typeof thresholds[threshold] !== 'number') {
          throw new Error(`Invalid or missing confidence threshold: ${threshold}`);
        }
      }
    }
    console.log('Main configuration structure validation passed');
  }
  /**
   * Expands domain references (from_domains_ref) in category signals
   */
  _expandDomainReferences(config, domainSources) {
    console.log('Expanding domain references in category signals');
    const expandedConfig = JSON.parse(JSON.stringify(config)); // Deep clone
    // Build domain lookup by source group
    const domainLookup = {};
    for (const [groupName, groupData] of Object.entries(domainSources)) {
      if (groupName === 'metadata') continue;
      domainLookup[groupName] = {
--
            domain: domainEntry.domain,
            type: domainEntry.type || null,
          });
        }
      }
    }
    // Store domain lookup for later use
    expandedConfig.domain_lookup = domainLookup;
    // Expand from_domains_ref in category signals
    for (const [categoryName, categorySignals] of Object.entries(expandedConfig.processing_config.category_signals)) {
      for (const [signalType, signalData] of Object.entries(categorySignals)) {
        if (signalData.from_domains_ref) {
          const ref = signalData.from_domains_ref;
          const sourceGroup = ref.source_group;
          const confidence = ref.confidence || 'medium';
          if (domainLookup[sourceGroup]) {
            const confidenceKey = `${confidence}_confidence`;
            const domains = domainLookup[sourceGroup][confidenceKey] || [];
            // Replace the reference with expanded domain list
            signalData.from_domains = domains.map((d) => d.domain);
            delete signalData.from_domains_ref; // Remove the reference
            console.log(
              `Expanded ${sourceGroup} ${confidence} domains for ${categoryName}.${signalType}: ${domains.length} domains`
            );
          } else {
            console.warn(`Warning - Unknown domain source group: ${sourceGroup}`);
          }
        }
      }
    }

