      // Contract validation - these assertions define the expected API behavior
      expect(response).toBeDefined();
      expect(response.sessionId).toBe(request.sessionId);
      expect(response.results).toHaveLength(1);

      const result = response.results[0];
      expect(result.emailId).toBe('test-email-001');
      expect(result.primaryCategory).toBeDefined();
      expect(result.confidence).toBeGreaterThanOrEqual(0);
      expect(result.confidence).toBeLessThanOrEqual(1);

      // Explainability trace contract
      expect(result.explainabilityTrace).toBeDefined();
      expect(result.explainabilityTrace.hardAssertions).toBeDefined();
