/**
 * Jest test setup for Classification Engine
 *
 * Configures testing environment for contract tests and explainability validation.
 */

// Global test configuration
jest.setTimeout(30000); // 30 seconds for contract tests

// Performance testing globals
global.performance = global.performance || {
  now: () => Date.now(),
  mark: () => {},
  measure: () => {},
};

// Console configuration for test output
const originalConsole = global.console;

beforeAll(() => {
  // Suppress console output during tests unless in debug mode
  if (!process.env.DEBUG_TESTS) {
    global.console = {
      ...originalConsole,
      log: jest.fn(),
      debug: jest.fn(),
      info: jest.fn(),
      warn: jest.fn(),
    };
  }
});

afterAll(() => {
  // Restore console
  global.console = originalConsole;
});

// Custom matchers for explainability traces
expect.extend({
  toHaveExplainabilityTrace(received: any) {
    const pass = received && received.explainabilityTrace &&
                 typeof received.explainabilityTrace === 'object';

    if (pass) {
      return {
        message: () => `Expected ${received} not to have explainability trace`,
        pass: true,
      };
    } else {
      return {
        message: () => `Expected ${received} to have explainability trace`,
        pass: false,
      };
    }
  },

  toHaveValidHardAssertions(received: any) {
    const hardAssertions = received?.explainabilityTrace?.hardAssertions;
    const pass = Array.isArray(hardAssertions);

    if (pass) {
      return {
        message: () => `Expected ${received} not to have valid hard assertions`,
        pass: true,
      };
    } else {
      return {
        message: () => `Expected ${received} to have valid hard assertions array`,
        pass: false,
      };
    }
  },

  toMeetPerformanceRequirements(received: any, maxDurationMs: number = 10000) {
    const duration = received?.processingDurationMs;
    const pass = typeof duration === 'number' && duration > 0 && duration < maxDurationMs;

    if (pass) {
      return {
        message: () => `Expected processing duration ${duration}ms to exceed ${maxDurationMs}ms`,
        pass: true,
      };
    } else {
      return {
        message: () => `Expected processing duration ${duration}ms to be between 0 and ${maxDurationMs}ms`,
        pass: false,
      };
    }
  },
});

// TypeScript declaration for custom matchers
declare global {
  namespace jest {
    interface Matchers<R> {
      toHaveExplainabilityTrace(): R;
      toHaveValidHardAssertions(): R;
      toMeetPerformanceRequirements(maxDurationMs?: number): R;
    }
  }
}

