+/**
+ * Jest snapshot serializer for explainability traces
+ *
+ * Provides clean, readable snapshots of complex explainability trace objects
+ * while filtering out non-deterministic fields like timestamps.
+ */
+
+module.exports = {
+  test(val) {
+    return val && typeof val === 'object' && val.explainabilityTrace;
+  },
+
+  serialize(val, config, indentation, depth, refs, printer) {
+    const trace = val.explainabilityTrace;
+
+    // Filter out non-deterministic fields for consistent snapshots
+    const sanitized = {
+      ...trace,
+      stageTimings: trace.stageTimings
+        ? Object.keys(trace.stageTimings).reduce((acc, stage) => {
+          acc[stage] = '<TIMING_FILTERED>';
+          return acc;
+        }, {})
+        : undefined,
+
+      hardAssertions: trace.hardAssertions?.map((assertion) => ({
+        ...assertion,
+        // Keep deterministic fields for validation
+        category: assertion.category,
+        triggered: assertion.triggered,
+        assertionType: assertion.assertionType,
+        matchedValue: assertion.matchedValue,
+        confidence: assertion.confidence,
+        reason: assertion.reason,
+      })),
+
+      finalDecisionReason: trace.finalDecisionReason,
+    };
+
+    return printer(sanitized, config, indentation, depth, refs);
+  },
+};
